// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');

describe('List pro skill approval', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('List pro skill approval', async function() {
    await driver.get("http://localhost:4200/home");
    await driver.manage().window().setRect({ width: 876, height: 400 });
    await driver.findElement(By.id("login_form_email")).click();
    await driver.findElement(By.id("login_form_email")).sendKeys("nguyen.hoang.thien");
    await driver.findElement(By.css(".ant-layout-content > div")).click();
    await driver.findElement(By.id("login_form_password")).click();
    await driver.findElement(By.id("login_form_password")).sendKeys("1");
    await driver.findElement(By.css(".ant-layout-content > div")).click();
    await driver.findElement(By.css(".ant-btn")).click();
    await driver.findElement(By.css(".ant-row:nth-child(5) .ant-card-body")).click();
    await driver.findElement(By.css(".ant-space-compact")).click();
    await driver.findElement(By.css(".anticon-logout path")).click();
    await driver.findElement(By.name("Search")).click();
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(1)")).getText() == "部署");
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(2)")).getText() == "バージョン");
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(3)")).getText() == "状態");
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(5)")).getText() == "最終更新者");
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(6)")).getText() == "最終更新日");
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(7)")).getText() == "公開日");
  });
});
